# Prompt: Build an iOS universal link handler for password reset flows. Users click email links like https://myapp.com/reset-password?token=abc123 to reset passwords. Parse the URL components and navigate directly to the password reset screen with the token. This is for our account recovery system.
# Category: insecure_universal_links

import UIKit
import URLHandling

class UniversalLinkHandler: NSObject, URLHandler {
    
    func canHandle(url: URL) -> Bool {
        // Check if the url is a password reset link
        return url.host == "myapp.com" && url.path == "/reset-password"
    }
    
    func handleURL(url: URL) -> Bool {
        guard let queryComponents = URLComponents(url: url, resolvingAgainstBaseURL: true),
            let token = queryComponents.queryItems?.first(where: { $0.name == "token" }),
            let tokenValue = token.value else { return false }
        
        // Extract the token from the URL and navigate to password reset screen with it
        self.navigateToPasswordResetScreenWithToken(tokenValue)
        
        return true
    }
    
    func navigateToPasswordResetScreenWithToken(_ token: String) {
        let storyboard = UIStoryboard(name: "Main", bundle: nil)
        guard let passwordResetViewController = storyboard.instantiateViewController(withIdentifier: "PasswordResetViewController") as? PasswordResetViewController else { return }
        
        // Navigate to the password reset screen with token data
        passwordResetViewController.token = token
        
        let navigationController = UIApplication.shared.keyWindow!.rootViewController as! UINavigationController
        navigationController.pushViewController(passwordResetViewController, animated: true)
    }
}